import type { Theme } from "@t3tools/shared/themes";

import { useTheme } from "../hooks/useTheme";

// ---------------------------------------------------------------------------
// Swatch — shows a mini preview of a theme's colour palette
// ---------------------------------------------------------------------------

function ThemeSwatch({ theme }: { theme: Theme }) {
  const { background, foreground, accent, sidebar } = theme.colors;

  return (
    <span
      className="inline-flex size-8 shrink-0 items-center justify-center overflow-hidden rounded-md border border-border shadow-sm"
      aria-hidden="true"
    >
      <span className="flex size-full flex-col">
        {/* top row — sidebar + editor */}
        <span className="flex flex-1">
          <span className="w-2/5" style={{ background: sidebar }} />
          <span className="flex-1" style={{ background }} />
        </span>
        {/* bottom row — status bar with accent dot */}
        <span
          className="flex h-1.5 items-center justify-center"
          style={{ background: foreground }}
        >
          <span
            className="size-1 rounded-full"
            style={{ background: accent }}
          />
        </span>
      </span>
    </span>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector — renders a card per available theme
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { currentTheme, availableThemes, setCustomTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Custom theme">
      {availableThemes.map((t) => {
        const selected = currentTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setCustomTheme(t.id)}
          >
            <ThemeSwatch theme={t} />

            <span className="flex min-w-0 flex-1 flex-col">
              <span className="text-sm font-medium">{t.name}</span>
              <span className="truncate text-xs opacity-70">
                {t.colors.background} / {t.colors.accent}
              </span>
            </span>

            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

