/**
 * Theme definitions for T3 Code.
 *
 * Each theme provides a full set of semantic color tokens, font preferences,
 * and metadata.  The built-in themes ship as plain objects so they can be
 * consumed by both the web and desktop apps without any runtime dependencies.
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Semantic color slots that every theme must define. */
export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

/** A complete theme definition. */
export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const FONT_SANS =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';

const t3Dark: Theme = {
  id: "t3-dark",
  name: "T3 Dark",
  colors: {
    background: "#0a0a0b",
    foreground: "#e4e4e7",
    accent: "#6d5dfc",
    sidebar: "#111113",
    editor: "#0a0a0b",
    terminal: "#09090b",
    statusBar: "#111113",
  },
  fontFamily: FONT_SANS,
  fontSize: 14,
};

const t3Light: Theme = {
  id: "t3-light",
  name: "T3 Light",
  colors: {
    background: "#ffffff",
    foreground: "#1c1c1e",
    accent: "#4f46e5",
    sidebar: "#f4f4f5",
    editor: "#ffffff",
    terminal: "#fafafa",
    statusBar: "#f4f4f5",
  },
  fontFamily: FONT_SANS,
  fontSize: 14,
};

const t3Midnight: Theme = {
  id: "t3-midnight",
  name: "T3 Midnight",
  colors: {
    background: "#030712",
    foreground: "#d1d5db",
    accent: "#818cf8",
    sidebar: "#0a1120",
    editor: "#030712",
    terminal: "#020617",
    statusBar: "#0a1120",
  },
  fontFamily: FONT_SANS,
  fontSize: 14,
};

// ---------------------------------------------------------------------------
// Registry
// ---------------------------------------------------------------------------

const BUILT_IN_THEMES: readonly Theme[] = [t3Dark, t3Light, t3Midnight];

const THEME_MAP = new Map<string, Theme>(BUILT_IN_THEMES.map((t) => [t.id, t]));

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Return the theme matching `id`, falling back to `"t3-dark"` when the id is
 * unknown.
 */
export function getTheme(id: string): Theme {
  return THEME_MAP.get(id) ?? t3Dark;
}

/** Return all available built-in themes. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

