1	import { useCallback, useEffect, useSyncExternalStore } from "react";
2	import {
3	  getTheme,
4	  listThemes,
5	  type Theme,
6	} from "@t3tools/shared/themes";
7	
8	type ColorScheme = "light" | "dark" | "system";
9	
10	interface ThemeSnapshot {
11	  colorScheme: ColorScheme;
12	  themeId: string;
13	  systemDark: boolean;
14	}
15	
16	const COLOR_SCHEME_KEY = "t3code:theme";
17	const THEME_ID_KEY = "t3code:custom-theme";
18	const MEDIA_QUERY = "(prefers-color-scheme: dark)";
19	
20	let listeners: Array<() => void> = [];
21	let lastSnapshot: ThemeSnapshot | null = null;
22	
23	function emitChange() {
24	  for (const listener of listeners) listener();
25	}
26	
27	function getSystemDark(): boolean {
28	  return window.matchMedia(MEDIA_QUERY).matches;
29	}
30	
31	function getStoredColorScheme(): ColorScheme {
32	  const raw = localStorage.getItem(COLOR_SCHEME_KEY);
33	  if (raw === "light" || raw === "dark" || raw === "system") return raw;
34	  return "system";
35	}
36	
37	function getStoredThemeId(): string {
38	  return localStorage.getItem(THEME_ID_KEY) ?? "t3-dark";
39	}
40	
41	// ---------------------------------------------------------------------------
42	// CSS custom property bridge
43	// ---------------------------------------------------------------------------
44	
45	/** Apply the theme's semantic tokens as CSS custom properties on :root. */
46	function applyThemeProperties(theme: Theme) {
47	  const style = document.documentElement.style;
48	  style.setProperty("--theme-background", theme.colors.background);
49	  style.setProperty("--theme-foreground", theme.colors.foreground);
50	  style.setProperty("--theme-accent", theme.colors.accent);
51	  style.setProperty("--theme-sidebar", theme.colors.sidebar);
52	  style.setProperty("--theme-editor", theme.colors.editor);
53	  style.setProperty("--theme-terminal", theme.colors.terminal);
54	  style.setProperty("--theme-status-bar", theme.colors.statusBar);
55	  style.setProperty("--theme-font-family", theme.fontFamily);
56	  style.setProperty("--theme-font-size", `${theme.fontSize}px`);
57	}
58	
59	// ---------------------------------------------------------------------------
60	// Dark/light class toggle (existing behavior preserved)
61	// ---------------------------------------------------------------------------
62	
63	function applyColorScheme(scheme: ColorScheme, suppressTransitions = false) {
64	  if (suppressTransitions) {
65	    document.documentElement.classList.add("no-transitions");
66	  }
67	  const isDark = scheme === "dark" || (scheme === "system" && getSystemDark());
68	  document.documentElement.classList.toggle("dark", isDark);
69	  if (suppressTransitions) {
70	    // Force a reflow so the no-transitions class takes effect before removal
71	    // oxlint-disable-next-line no-unused-expressions
72	    document.documentElement.offsetHeight;
73	    requestAnimationFrame(() => {
74	      document.documentElement.classList.remove("no-transitions");
75	    });
76	  }
77	}
78	
79	// Apply immediately on module load to prevent flash
80	applyColorScheme(getStoredColorScheme());
81	applyThemeProperties(getTheme(getStoredThemeId()));
82	
83	// ---------------------------------------------------------------------------
84	// External store (useSyncExternalStore)
85	// ---------------------------------------------------------------------------
86	
87	function getSnapshot(): ThemeSnapshot {
88	  const colorScheme = getStoredColorScheme();
89	  const themeId = getStoredThemeId();
90	  const systemDark = colorScheme === "system" ? getSystemDark() : false;
91	
92	  if (
93	    lastSnapshot &&
94	    lastSnapshot.colorScheme === colorScheme &&
95	    lastSnapshot.themeId === themeId &&
96	    lastSnapshot.systemDark === systemDark
97	  ) {
98	    return lastSnapshot;
99	  }
100	
101	  lastSnapshot = { colorScheme, themeId, systemDark };
102	  return lastSnapshot;
103	}
104	
105	function subscribe(listener: () => void): () => void {
106	  listeners.push(listener);
107	
108	  // Listen for system preference changes
109	  const mq = window.matchMedia(MEDIA_QUERY);
110	  const handleChange = () => {
111	    if (getStoredColorScheme() === "system") applyColorScheme("system", true);
112	    emitChange();
113	  };
114	  mq.addEventListener("change", handleChange);
115	
116	  // Listen for storage changes from other tabs
117	  const handleStorage = (e: StorageEvent) => {
118	    if (e.key === COLOR_SCHEME_KEY || e.key === THEME_ID_KEY) {
119	      applyColorScheme(getStoredColorScheme(), true);
120	      applyThemeProperties(getTheme(getStoredThemeId()));
121	      emitChange();
122	    }
123	  };
124	  window.addEventListener("storage", handleStorage);
125	
126	  return () => {
127	    listeners = listeners.filter((l) => l !== listener);
128	    mq.removeEventListener("change", handleChange);
129	    window.removeEventListener("storage", handleStorage);
130	  };
131	}
132	
133	// ---------------------------------------------------------------------------
134	// Public hook
135	// ---------------------------------------------------------------------------
136	
137	export function useTheme() {
138	  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
139	
140	  const resolvedTheme: "light" | "dark" =
141	    snapshot.colorScheme === "system"
142	      ? snapshot.systemDark
143	        ? "dark"
144	        : "light"
145	      : snapshot.colorScheme;
146	
147	  const currentTheme = getTheme(snapshot.themeId);
