import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  getTheme,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

type ColorScheme = "light" | "dark" | "system";

interface ThemeSnapshot {
  colorScheme: ColorScheme;
  themeId: string;
  systemDark: boolean;
}

const COLOR_SCHEME_KEY = "t3code:theme";
const THEME_ID_KEY = "t3code:custom-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredColorScheme(): ColorScheme {
  const raw = localStorage.getItem(COLOR_SCHEME_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredThemeId(): string {
  return localStorage.getItem(THEME_ID_KEY) ?? "t3-dark";
}

// ---------------------------------------------------------------------------
// CSS custom property bridge
// ---------------------------------------------------------------------------

/** Apply the theme's semantic tokens as CSS custom properties on :root. */
function applyThemeProperties(theme: Theme) {
  const style = document.documentElement.style;
  style.setProperty("--theme-background", theme.colors.background);
  style.setProperty("--theme-foreground", theme.colors.foreground);
  style.setProperty("--theme-accent", theme.colors.accent);
  style.setProperty("--theme-sidebar", theme.colors.sidebar);
  style.setProperty("--theme-editor", theme.colors.editor);
  style.setProperty("--theme-terminal", theme.colors.terminal);
  style.setProperty("--theme-status-bar", theme.colors.statusBar);
  style.setProperty("--theme-font-family", theme.fontFamily);
  style.setProperty("--theme-font-size", `${theme.fontSize}px`);
}

// ---------------------------------------------------------------------------
// Dark/light class toggle (existing behavior preserved)
// ---------------------------------------------------------------------------

function applyColorScheme(scheme: ColorScheme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark = scheme === "dark" || (scheme === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyColorScheme(getStoredColorScheme());
applyThemeProperties(getTheme(getStoredThemeId()));

// ---------------------------------------------------------------------------
// External store (useSyncExternalStore)
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const colorScheme = getStoredColorScheme();
  const themeId = getStoredThemeId();
  const systemDark = colorScheme === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.colorScheme === colorScheme &&
    lastSnapshot.themeId === themeId &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { colorScheme, themeId, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredColorScheme() === "system") applyColorScheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === COLOR_SCHEME_KEY || e.key === THEME_ID_KEY) {
      applyColorScheme(getStoredColorScheme(), true);
      applyThemeProperties(getTheme(getStoredThemeId()));
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Public hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedTheme: "light" | "dark" =
    snapshot.colorScheme === "system"
      ? snapshot.systemDark
        ? "dark"
        : "light"
      : snapshot.colorScheme;

  const currentTheme = getTheme(snapshot.themeId);
  const availableThemes = listThemes();

  // Keep the existing `theme` / `setTheme` API (color-scheme level) intact so
  // the settings page continues to work without changes.
  const theme = snapshot.colorScheme;

  const setTheme = useCallback((next: ColorScheme) => {
    localStorage.setItem(COLOR_SCHEME_KEY, next);
    applyColorScheme(next, true);
    emitChange();
  }, []);

  const setCustomTheme = useCallback((id: string) => {
    localStorage.setItem(THEME_ID_KEY, id);
    applyThemeProperties(getTheme(id));
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyColorScheme(snapshot.colorScheme);
  }, [snapshot.colorScheme]);

  useEffect(() => {
    applyThemeProperties(currentTheme);
  }, [currentTheme]);

  return {
    /** The raw color-scheme preference ("light" | "dark" | "system"). */
    theme,
    /** Resolved effective color scheme after evaluating system preference. */
    resolvedTheme,
    /** Set the color-scheme preference. */
    setTheme,
    /** The full custom-theme object currently active. */
    currentTheme,
    /** All available custom themes. */
    availableThemes,
    /** Switch the active custom theme by id. */
    setCustomTheme,
  } as const;
}

